    (965, 'Occhio non vede, cuore non duole... ma online tutto resta!', 'phrase', '00c22956b78bdd70d5c49529617f059759c65acd77d432300865c94cf68feff0', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_022", "note_culturale": "Variazione di un detto popolare."}', NULL),
    (966, 'Silmä ei näe, sydän ei sure... mutta verkossa kaikki jää!', 'phrase', '39d11dc8497db481c2e1cbe7f5c45031bf180ea2ebf73e770487845b7d134567', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_022", "note_culturale": "Variazione di un detto popolare."}', NULL),
    (967, 'Out of sight, out of mind... but online everything stays!', 'phrase', '2d67c6fad06274798e74fb884d6867adf900a315a2b100e63fe5d1d0486739b5', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_022", "note_culturale": "Variazione di un detto popolare."}', NULL),
    (968, 'La rete non dimentica, quindi pensa prima di postare!', 'phrase', '3539dca645fb05c36b179d55dbf2b74ad09c36d4ec5f509916dc7a6764cede76', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_023", "note_culturale": "Avvertimento comune sull''uso dei social media."}', NULL),
    (969, 'Verkko ei unohda, joten ajattele ennen kuin julkaiset!', 'phrase', '25016dcfb80b333613f8bb05b2ce2ee20117c4b40c5b5d5e0a0e6707a57152c1', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_023", "note_culturale": "Avvertimento comune sull''uso dei social media."}', NULL),
    (970, 'The internet never forgets, so think before you post!', 'phrase', 'c21d86031fab93f3d94b9bfd18774ce82d56c11e92970eecafbba35e2a918112', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_023", "note_culturale": "Avvertimento comune sull''uso dei social media."}', NULL),
    (971, 'Cyberbullismo? Non fare il gradasso dietro uno schermo!', 'phrase', '5b30db96e8272e5bf4aaac423427fbee3c0729c54d334886dab4c682b93db7d4', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_024", "note_culturale": "Critica all''anonimato che alimenta il bullismo."}', NULL),
    (972, 'Nettikiusaaminen? Älä esitä kovaa poikaa näytön takana!', 'phrase', 'd148d5e088f63416ab7b15c908eeae7f536ce0d556af05aa09df320e8416c43b', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_024", "note_culturale": "Critica all''anonimato che alimenta il bullismo."}', NULL),
    (973, 'Cyberbullying? Don''t be a tough guy behind a screen!', 'phrase', '39d0faa8da3854363f40953648aefb5cbee093905207d96b6e5c5870bd71a58b', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_024", "note_culturale": "Critica all''anonimato che alimenta il bullismo."}', NULL),
    (974, 'Se non lo diresti in faccia, non scriverlo online!', 'phrase', '06e86a946707cea531543a81d4fba35e4343f5192605b324cb1e048054cd8f55', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_025", "note_culturale": "Promemoria di applicare le stesse regole di conversazione online e offline."}', NULL),
    (975, 'Jos et sanoisi sitä kasvoista kasvoihin, älä kirjoita sitä verkkoon!', 'phrase', 'd0867bc70dc6b1649ca7dbfe81ac037779f257184555c7e78ff6237c2f88d9b4', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_025", "note_culturale": "Promemoria di applicare le stesse regole di conversazione online e offline."}', NULL),
    (976, 'If you wouldn''t say it to their face, don''t write it online!', 'phrase', 'bb8b36f601db27f8c5b2bff69d1bf5bbf5fbae31eb61ebf050cc3fc5d707b810', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_025", "note_culturale": "Promemoria di applicare le stesse regole di conversazione online e offline."}', NULL),
    (977, 'Non abboccare all''amo, verifica sempre le fonti!', 'phrase', '8808196e7781797260ff18cdbc7681fda65a80d0ea704913efc7a1f48fd0bf79', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_026", "note_culturale": "Metafora della pesca applicata alla disinformazione."}', NULL),
    (978, 'Älä mene lankaan, tarkista aina lähteet!', 'phrase', '8f2674c6f50b9334ee074c6e30c075ce634c8e2b74b90b11df683bdf2fa284f2', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_026", "note_culturale": "Metafora della pesca applicata alla disinformazione."}', NULL),
    (979, 'Don''t take the bait, always verify your sources!', 'phrase', 'a96c91adb90aa0f17abf63a21dac6b50be1276663e13bc6dba44a51ac0a6f908', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_026", "note_culturale": "Metafora della pesca applicata alla disinformazione."}', NULL),
    (980, 'La privacy è un diritto, non un optional!', 'phrase', 'df6f947c62abef0c389d04f227864195087429ebdb85f9f6acdc59e764fc285f', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_027", "note_culturale": "Enfatizza l''importanza della protezione dei dati personali."}', NULL),
