    (987, 'Ole fiksu, suojaa tietosi!', 'phrase', '728bb3ff3cb2a89d96a2fb3de51da1ed5a9a5785a17b0db8e1842dfa4cdc147e', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_029", "note_culturale": "Incoraggia a prendere precauzioni per la sicurezza online."}', NULL),
    (988, 'Be smart, protect your data!', 'phrase', 'ebec75a85bb20d2bebfc3a42434f2d7472d2e21c09d249a0c774960fabce158d', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_029", "note_culturale": "Incoraggia a prendere precauzioni per la sicurezza online."}', NULL),
    (989, 'Non fare il passo più lungo della gamba online!', 'phrase', 'b604557572769cfb5bce2cbc1b200ae3a6fcabfcf869afabd46c4a83c1fce90c', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_030", "note_culturale": "Consiglio di moderazione e prudenza nell''uso dei social media."}', NULL),
    (990, 'Älä ota liian suurta askelta verkossa!', 'phrase', '4a7228e50de061f76b0f0cc5c7535ade1f01f28ff1dc15e0d6b960ce2eb331ec', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_030", "note_culturale": "Consiglio di moderazione e prudenza nell''uso dei social media."}', NULL),
    (991, 'Don''t bite off more than you can chew online!', 'phrase', 'c9a916454b69d528f214a5cf85bf00cd37dd79158df1ff26f08910b62a80a6ad', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_030", "note_culturale": "Consiglio di moderazione e prudenza nell''uso dei social media."}', NULL),
    (992, 'Occhio non vede, cuore non duole... ma online, tutto resta!', 'phrase', '880abe8631f26aeb955218ff37276beb18e0b28fa0b44f5f986102f85fa0175d', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_031", "note_culturale": "Rielaborazione di un detto popolare per l''era digitale."}', NULL),
    (993, 'Poissa silmistä, poissa mielestä... mutta verkossa kaikki jää!', 'phrase', '40c512d0bd03ff29915f0aae6962af6d500a37f4b14a0ba7b29e5d2a7fbf8b62', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_031", "note_culturale": "Rielaborazione di un detto popolare per l''era digitale."}', NULL),
    (994, 'Out of sight, out of mind... but online, everything stays!', 'phrase', '84a8b2eae5284dcf98427f3aa5810527fba41b74fd1e68c0e59d248587b27cfb', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_031", "note_culturale": "Rielaborazione di un detto popolare per l''era digitale."}', NULL),
    (995, 'La rete non dimentica, quindi pensaci due volte prima di postare!', 'phrase', '053b3469b7c30afa7c4edf13aff807d3dedcbfb3d0e7de1f9cd5b1828e1b724a', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_032", "note_culturale": "Riflette la permanenza delle informazioni online."}', NULL),
    (996, 'Internet ei unohda, joten mieti kahdesti ennen kuin julkaiset!', 'phrase', 'c503c8352e63610a1fd1b36ded910d3e40e30ba17e31f574d6d8192d1901c412', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_032", "note_culturale": "Riflette la permanenza delle informazioni online."}', NULL),
    (997, 'The internet doesn''t forget, so think twice before you post!', 'phrase', '12b9a438c018d955b18416471a19ee846ab93de15bc21419ca9c74cc1a78a884', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_032", "note_culturale": "Riflette la permanenza delle informazioni online."}', NULL),
    (998, 'Non fare agli altri online quello che non vorresti fosse fatto a te.', 'phrase', 'ced14b95fa81a5e25b527156753fea90481957a18b62469957068907a01599c7', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_033", "note_culturale": "Applicazione di un principio morale universale all''ambiente online."}', NULL),
    (999, 'Älä tee muille verkossa sitä, mitä et haluaisi itsellesi tehtävän.', 'phrase', '20989b759ea24403f92d6bc5fbaa0c22107e5a05ff4d1b75aa2707453897032b', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_033", "note_culturale": "Applicazione di un principio morale universale all''ambiente online."}', NULL),
    (1000, 'Don''t do to others online what you wouldn''t want done to you.', 'phrase', 'c082b043af55ecf78331a760d521f1622a934ffcf91e031a8c1c9250ceb94fec', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_033", "note_culturale": "Applicazione di un principio morale universale all''ambiente online."}', NULL),
    (1001, 'In rete, la tua reputazione è oro colato: proteggila!', 'phrase', '0f0091962206487f1074123a2932a4af50e9ab2a7c79cf87cdd605dccafd4b8e', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_034", "note_culturale": "Metafora del valore della reputazione nell''era digitale."}', NULL),
    (1002, 'Verkossa maineesi on kultaa: suojele sitä!', 'phrase', '44ced90b5b737d0122e0586c270c647cab6e94c34fd6815ee754745c18198108', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_034", "note_culturale": "Metafora del valore della reputazione nell''era digitale."}', NULL),
    (1003, 'Online, your reputation is gold: protect it!', 'phrase', '3b057e523f59e222cb3e3bf0b98fea845b8d7d54f694d6c6ee36203567c1261f', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_034", "note_culturale": "Metafora del valore della reputazione nell''era digitale."}', NULL),
    (1004, 'Dietro ogni schermo c''è una persona: ricordalo prima di insultare!', 'phrase', 'b5b4d2835b443f6df9261c7eacae6952f53dde9ba93abe7491d70c4c5c12012e', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_035", "note_culturale": "Sottolinea la necessità di empatia nelle interazioni online."}', NULL),
    (1005, 'Jokaisen näytön takana on ihminen: muista se ennen kuin loukkaat!', 'phrase', '0819af9a7a51319861c737527115b6a55a61d233e9e6e1f573d13a00d8df0a08', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_035", "note_culturale": "Sottolinea la necessità di empatia nelle interazioni online."}', NULL),
    (1006, 'Behind every screen is a person: remember that before you insult!', 'phrase', 'bdee98002aa5008d1ee8aea73e3144e88689e8b601b694ad2eab46673d8b774e', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_035", "note_culturale": "Sottolinea la necessità di empatia nelle interazioni online."}', NULL),
    (1007, 'Chi semina vento, raccoglie tempesta... di commenti negativi!', 'phrase', 'e46ac17806a78c0f24911ead340266ea19ea829944081c67900694c0489feed8', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_036", "note_culturale": "Adattamento di un proverbio classico al contesto dei social media."}', NULL),
    (1008, 'Joka tuulta kylvää, se myrskyä niittää... negatiivisten kommenttien myrskyn!', 'phrase', '07ad6234863eb28ef8def42664ad7f974975d50a6b1b8990d1867e8de3336109', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_036", "note_culturale": "Adattamento di un proverbio classico al contesto dei social media."}', NULL),
