    (1010, 'La privacy è un diritto, non un optional: difendila online!', 'phrase', 'ee39826e99f4b627ba8fd411cab1c6c826e8cea60448ec8d40b132196db2fe64', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_037", "note_culturale": "Enfatizza la necessità di consapevolezza e azione per proteggere la privacy."}', NULL),
    (1011, 'Yksityisyys on oikeus, ei valinnainen: puolusta sitä verkossa!', 'phrase', 'd0b7b157ac1b2f170dc41e2e1f7e4fbb3dcae595fe1082205ba305cd580deae7', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_037", "note_culturale": "Enfatizza la necessità di consapevolezza e azione per proteggere la privacy."}', NULL),
    (1012, 'Privacy is a right, not an option: defend it online!', 'phrase', '0b03594ab900dd4610240f7f416831b56333b771c754b07c5976538476a29bdd', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_037", "note_culturale": "Enfatizza la necessità di consapevolezza e azione per proteggere la privacy."}', NULL),
