    (1016, 'Prima di condividere, verifica: non fare la figura del pesce d''aprile tutto l''anno!', 'phrase', '55544e8d8fa8015d15513c9157323cd612a3a6b22bbc302bc8e85392817b193f', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_039", "note_culturale": "Utilizzo della figura del pesce d''aprile per evidenziare l''importanza della verifica."}', NULL),
    (1017, 'Ennen jakamista, tarkista: älä tee aprillipilaa itsestäsi koko vuoden!', 'phrase', '93f88a9e5b222eac88a472c8cec5eda5c35f7abcf36de760883e3d0295f0c534', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_039", "note_culturale": "Utilizzo della figura del pesce d''aprile per evidenziare l''importanza della verifica."}', NULL),
    (1018, 'Before sharing, verify: don''t make yourself an April Fool all year round!', 'phrase', 'fb8f980fef958de848a0a1b9f08e104043c8520d691f85d49567289cc65d462d', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_039", "note_culturale": "Utilizzo della figura del pesce d''aprile per evidenziare l''importanza della verifica."}', NULL),
    (1019, 'Navigare in rete è un gioco da ragazzi, ma usare la testa è da adulti!', 'phrase', '5134eb4eb43e3e544547500f508b3b0b176017669bc729b3fdbcecc69ecfff20', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_040", "note_culturale": "Contrapposizione tra la facilità d''uso e la necessità di responsabilità."}', NULL),
    (1020, 'Verkossa surffailu on lasten leikkiä, mutta pään käyttö on aikuisille!', 'phrase', '3323b28de2cde8fb8fdd0ff2aad88469c4099eccc855691e72f622101c572c7d', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_040", "note_culturale": "Contrapposizione tra la facilità d''uso e la necessità di responsabilità."}', NULL),
    (1021, 'Surfing the net is child''s play, but using your head is for adults!', 'phrase', 'b5e5c6895d71091cf1514a51d18d4013fda24822442d082166a3c0e92e23474f', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_040", "note_culturale": "Contrapposizione tra la facilità d''uso e la necessità di responsabilità."}', NULL),
    (1022, 'Prima di postare, conta fino a dieci!', 'phrase', 'd80187227b795406af6851476fd1f6330f790c82e3bca370b9818f8f97502cfd', 'A2', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_041", "note_culturale": "Simile al consiglio di ''dormirci su'' prima di prendere decisioni importanti."}', NULL),
    (1023, 'Ennen kuin julkaiset, laske kymmeneen!', 'phrase', '30d44b92e4287d13a014f60a9f787a34566d431bf8d398cc09b216d0977ddb4f', 'A2', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_041", "note_culturale": "Simile al consiglio di ''dormirci su'' prima di prendere decisioni importanti."}', NULL),
    (1024, 'Before you post, count to ten!', 'phrase', '6e255d5086fed1d9776c37df55a824ce00d054ec842f5772105bd01a3bb34ccf', 'A2', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_041", "note_culturale": "Simile al consiglio di ''dormirci su'' prima di prendere decisioni importanti."}', NULL),
    (1025, 'La privacy è un tesoro, proteggila come gli occhi tuoi!', 'phrase', 'eef3c5aa40fa390979e80f12fe92a501a1e856cfd2b4564a21ef45f036a136f1', 'A2', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_042", "note_culturale": "Paragone con qualcosa di molto prezioso e insostituibile."}', NULL),
    (1026, 'Yksityisyys on aarre, suojele sitä kuin silmäterääsi!', 'phrase', '36b39e2edfba9e193c17bb31761365a6ad97692f354416dabf7f7ab16099c0a3', 'A2', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_042", "note_culturale": "Paragone con qualcosa di molto prezioso e insostituibile."}', NULL),
    (1027, 'Privacy is a treasure, protect it like your own eyes!', 'phrase', 'a657bf3ec072ebd24ab60d7f6cf506641e4b480510aea06f07112f56d22b0f6e', 'A2', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_042", "note_culturale": "Paragone con qualcosa di molto prezioso e insostituibile."}', NULL),
    (1028, 'Verba volant, scripta manent... e online rimangono per sempre!', 'phrase', 'a9f9c385b291dae62da2fa7d984d293c7b6d84b97eaf596ccc738d421947d824', 'A2', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_043", "note_culturale": "Adattamento di un detto latino all''era digitale."}', NULL),
    (1029, 'Sanat lentävät, kirjoitukset jäävät... ja verkossa ne säilyvät ikuisesti!', 'phrase', '10ca493cea4528244f9cf3f9c1a2295b5b7d322912a3c1b6c7591b071122599b', 'A2', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_043", "note_culturale": "Adattamento di un detto latino all''era digitale."}', NULL),
    (1030, 'Words fly away, writings remain... and online they stay forever!', 'phrase', 'eb3a29e7b00b143cc612731374103aaa6e785c3ccebd4707b69057d3e194e2fd', 'A2', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_043", "note_culturale": "Adattamento di un detto latino all''era digitale."}', NULL),
    (1031, 'Non prendere tutto oro colato quello che luccica online!', 'phrase', 'c6db69906b94459a2fa890e58e7f496d90da72b5df4ab3e51d0e036b6750afa8', 'A2', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_044", "note_culturale": "Adattamento di un proverbio popolare al contesto della disinformazione online."}', NULL),
    (1032, 'Älä usko kaikkea kultana, mikä kiiltää verkossa!', 'phrase', '50e095ca454788707bec784dcd5ca6362e06a57eaff95ad3ff92d4efb63ad5f7', 'A2', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_044", "note_culturale": "Adattamento di un proverbio popolare al contesto della disinformazione online."}', NULL),
    (1033, 'Don''t believe everything that glitters online is gold!', 'phrase', 'b2069e20d5e6981a515ce8983f9a3496ce9a5db1ad404bf933a32e31c34a7674', 'A2', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_044", "note_culturale": "Adattamento di un proverbio popolare al contesto della disinformazione online."}', NULL),
    (1034, 'Chi è causa del suo mal, pianga se stesso... se viene bannato!', 'phrase', 'f3bf5fb5ca3f7829fdfe62b3b682554f38f45b8fdda9dad0914217b84ae8e904', 'A2', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_045", "note_culturale": "Adattamento di un proverbio popolare al contesto delle regole delle comunità online."}', NULL),
    (1035, 'Joka on oman onnensa seppä, itkeköön itseään... jos hänet bannataan!', 'phrase', '665a4eddd93387feee7fc2f4866d2c260b1adae9f43e7c2f8d423d6075448cda', 'A2', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_045", "note_culturale": "Adattamento di un proverbio popolare al contesto delle regole delle comunità online."}', NULL),
    (1036, 'He who is the cause of his own misfortune, let him weep for himself... if he gets banned!', 'phrase', '2cb4ee0f88432d279a161f786ecd86971840c1185f84c020ce25b092dcfe8906', 'A2', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_045", "note_culturale": "Adattamento di un proverbio popolare al contesto delle regole delle comunità online."}', NULL),
    (1037, 'Un''immagine vale più di mille parole... ma controlla sempre la fonte!', 'phrase', 'bd9bc8b340f694163291d5a96d62fb7f7998a129918462e5c4b4dfb89e6a653f', 'A2', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_046", "note_culturale": "Adattamento di un detto popolare al contesto della manipolazione delle immagini online."}', NULL),
    (1038, 'Yksi kuva kertoo enemmän kuin tuhat sanaa... mutta tarkista aina lähde!', 'phrase', '71aef5331b22b5d9c9b4fee6e1f811abb368694df026f44652e38bd8649de57d', 'A2', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_046", "note_culturale": "Adattamento di un detto popolare al contesto della manipolazione delle immagini online."}', NULL),
    (1039, 'A picture is worth a thousand words... but always check the source!', 'phrase', 'adc8db00ddb381c5f8c3a4b676f01f593e9e8423472d7e6cd1f90274b4625b6b', 'A2', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_046", "note_culturale": "Adattamento di un detto popolare al contesto della manipolazione delle immagini online."}', NULL),
    (1040, 'Il web non dimentica... pensa bene prima di condividere!', 'phrase', '20b99730435c39a1e2cdde8bbb7a967e49eabcac0d4015dfb7c1c87aabcac812', 'A2', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_047", "note_culturale": "Avvertimento sulla difficoltà di cancellare completamente le informazioni dal web."}', NULL),
    (1041, 'Verkko ei unohda... mieti tarkkaan ennen kuin jaat!', 'phrase', 'e7d13f1f8edd6780b9837e4142efda9646c1512d2ce0b2d13ddd6d6bf0c63382', 'A2', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_047", "note_culturale": "Avvertimento sulla difficoltà di cancellare completamente le informazioni dal web."}', NULL),
    (1042, 'The web doesn''t forget... think carefully before sharing!', 'phrase', '1d22103489b680a0f9ec035c890cadee370d887e5d92d6c21fc3123a3f388791', 'A2', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_etica_digitale_047", "note_culturale": "Avvertimento sulla difficoltà di cancellare completamente le informazioni dal web."}', NULL),
