    (1044, 'Menikö sisaresi lopulta naimisiin?', 'phrase', '8fad35dc7afd6f6d88b5dc83b680f4d71cbe3efb5cd917fcc896fc369c0fb939', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_001", "note_culturale": null}', NULL),
    (1045, 'Did your sister finally get married?', 'phrase', 'e2dca6a859f4afbd0a05c385f0ccc7cc466f3c9e37d42dfe223e0ce33f11793d', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_001", "note_culturale": null}', NULL),
